function makeCounter() {
  let count = 0;
  return () => ++count;
}
const next = makeCounter();
console.log(next(), next(), next());

def make_closure(x):
  def inner(y):
    return x + y
  return inner
add5 = make_closure(5)
print(add5(3))

class Adder {
  private final int x;
  Adder(int x) { this.x = x; }
  int apply(int y) { return x + y; }
}

